mapper.select:
SELECT d.id, d.version_id AS versionId, d.sequence_no AS sequenceNo, d.atomic_command_id AS atomicCommandId, d.atomic_command_code AS atomicCommandCode, d.args_template AS argsTemplate, d.delay_min_ms AS delayMinMs, d.delay_max_ms AS delayMaxMs, d.timeout_ms AS timeoutMs, d.idempotency_key AS idempotencyKey, d.success_assertion AS successAssertion, d.failure_strategy AS failureStrategy, d.status, d.create_time AS createTime, d.update_time AS updateTime FROM agent_memory_version_detail d
AND d.version_id = #{pageRequest.versionId}
AND d.atomic_command_code LIKE CONCAT('%', #{pageRequest.atomicCommandCode}, '%')
AND d.status = #{pageRequest.status}
ORDER BY d.sequence_no ASC
